CREATE OR REPLACE FUNCTION public.trg_cleanup_transaction_on_rejection()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
-- Eğer statü "Onay Bekliyor"dan "Kapalı/Reddedildi" statülerinden birine geçerse
IF OLD.status IN ('awaiting_client_approval', 'awaiting-approval') 
    AND NEW.status IN ('client_approval_closed', 'client_no_response_closed') THEN
    
    -- A) Önce bu göreve ait ana işlemlerin alt (child) işlemlerini sil
    DELETE FROM transactions WHERE parent_id IN (
        SELECT id FROM transactions WHERE task_id = NEW.id
    );
    
    -- B) Ardından ana işlemi (transaction) sil
    DELETE FROM transactions WHERE task_id = NEW.id;

END IF;

RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.export_mini_db()
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    tbl record;
    result jsonb := '{}'::jsonb;
    rows jsonb;
BEGIN
    -- public şemasındaki tüm tabloları dön
    FOR tbl IN 
        SELECT table_name 
        FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_type = 'BASE TABLE'
    LOOP
        -- Her tablodan 3 kayıt çek ve JSON'a çevir
        EXECUTE format('SELECT COALESCE(jsonb_agg(row_to_json(t)), ''[]''::jsonb) FROM (SELECT * FROM public.%I LIMIT 3) t', tbl.table_name)
        INTO rows;
        
        -- Sonuç objesine tablo adıyla birlikte ekle
        result := jsonb_set(result, ARRAY[tbl.table_name], rows);
    END LOOP;
    
    RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION public.trg_on_task_delete_cleanup()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- A) Bu göreve bağlı TAHAKKUKLARI (accruals) sil
    DELETE FROM accruals WHERE task_id = OLD.id;

    -- B) Bu göreve bağlı DAVA KAYITLARINI (suits) sil
    DELETE FROM suits WHERE task_id = OLD.id;

    -- C) Bu göreve bağlı TRANSACTION GEÇMİŞİNİ SİL (Hiyerarşik Silme)
    DELETE FROM transactions WHERE parent_id IN (
        SELECT id FROM transactions WHERE task_id = OLD.id
    );
    DELETE FROM transactions WHERE task_id = OLD.id;

    -- D) Bu göreve bağlı BİLDİRİMLERİ (mail_notifications) güncelle/sil
    UPDATE mail_notifications 
    SET associated_task_id = NULL 
    WHERE associated_task_id = OLD.id AND status = 'sent';

    DELETE FROM mail_notifications 
    WHERE associated_task_id = OLD.id AND status != 'sent';

    -- E) ALT GÖREVLERİ SİL (details->>'parent_task_id' kontrolü ile)
    DELETE FROM tasks WHERE details->>'parent_task_id' = OLD.id;

    -- 🔥 F) GÖREV GEÇMİŞİNİ SİLMEK YERİNE, "SİLİNDİ" LOGU EKLİYORUZ
    -- Eski 'DELETE FROM task_history...' satırını kaldırdık!
    
    INSERT INTO public.task_history (
        task_id,
        action,
        user_id,
        details
    ) VALUES (
        OLD.id,
        'task_deleted',
        auth.uid(), -- Supabase üzerinden işlemi yapan kullanıcının ID'sini otomatik çeker
        jsonb_build_object(
            'note', 'Görev sistemden silindi.',
            'task_title', OLD.title,
            'task_type_id', OLD.task_type_id,
            'ip_record_id', OLD.ip_record_id,
            'deleted_at', NOW()
        )
    );

    -- G) GÖREVE EKLENEN BELGELERİ SİL (task_documents)
    DELETE FROM task_documents WHERE task_id = OLD.id;

    -- İşlemi tamamla ve devam et
    RETURN OLD;
END;
$function$
